/// Fold icmp Pred min|max(X, Y), Z.
Instruction *InstCombinerImpl::foldICmpWithMinMax(Instruction &I,
                                                  MinMaxIntrinsic *MinMax,
                                                  Value *Z, CmpPredicate Pred) {
  Value *X = MinMax->getLHS();
  Value *Y = MinMax->getRHS();

  // Check if we have icmp eq (smin (smax X, C1), C2), X
  // %v2 = tail call i32 @llvm.smax.i32(i32 %v1, i32 -155)
  // %v3 = tail call i32 @llvm.smin.i32(i32 %v2, i32 100)
  // %v4 = icmp eq i32 %v1, %v3
  if (ICmpInst::isEquality(Pred)) {
    if (auto *InnerMinMax = dyn_cast<MinMaxIntrinsic>(Z == X ? Y : X)) {
      Value *Other = Z == X ? Z : Y;
      if (InnerMinMax->getLHS() == Other || InnerMinMax->getRHS() == Other) {
        // We match: X == smin(smax(X, C1), C2) -> X >= C1 && X <= C2 -> (X - C1) <= (C2 - C1)
        ConstantInt *C1, *C2;
        Value *XFromInner = InnerMinMax->getLHS() == Other ? InnerMinMax->getRHS() : InnerMinMax->getLHS();
        if (match(XFromInner, m_ConstantInt(C1)) &&
            match(Z == X ? X : Y, m_ConstantInt(C2))) {
            // Need to match C1 properly depending on MinMax
        }
        if (match(InnerMinMax->getRHS(), m_ConstantInt(C1)) &&
            match(MinMax->getRHS(), m_ConstantInt(C2)) && InnerMinMax->getLHS() == Other) {
          // Verify it's min(max) or max(min)
          if ((MinMax->getIntrinsicID() == Intrinsic::smin && InnerMinMax->getIntrinsicID() == Intrinsic::smax) ||
              (MinMax->getIntrinsicID() == Intrinsic::smax && InnerMinMax->getIntrinsicID() == Intrinsic::smin) ||
              (MinMax->getIntrinsicID() == Intrinsic::umin && InnerMinMax->getIntrinsicID() == Intrinsic::umax) ||
              (MinMax->getIntrinsicID() == Intrinsic::umax && InnerMinMax->getIntrinsicID() == Intrinsic::umin)) {
            // make sure C1 < C2 for min(max(X, C1), C2) -> X >= C1 && X <= C2
            ConstantInt *LowC = C1;
            ConstantInt *HighC = C2;
            if (MinMax->getIntrinsicID() == Intrinsic::smax || MinMax->getIntrinsicID() == Intrinsic::umax)
              std::swap(LowC, HighC);

            bool IsSigned = MinMax->getIntrinsicID() == Intrinsic::smin || MinMax->getIntrinsicID() == Intrinsic::smax;
            if (IsSigned ? LowC->getValue().sle(HighC->getValue()) : LowC->getValue().ule(HighC->getValue())) {
               Value *Sub = Builder.CreateSub(Other, LowC);
               Constant *Diff = ConstantInt::get(Other->getType(), HighC->getValue() - LowC->getValue());
               return new ICmpInst(Pred == ICmpInst::ICMP_EQ ? ICmpInst::ICMP_ULE : ICmpInst::ICMP_UGT, Sub, Diff);
            }
          }
        }
      }
    }
  }

  if (ICmpInst::isSigned(Pred) && !MinMax->isSigned())
    return nullptr;
  if (ICmpInst::isUnsigned(Pred) && MinMax->isSigned()) {
    // Revert the transform signed pred -> unsigned pred
    // TODO: We can flip the signedness of predicate if both operands of icmp
    // are negative.
    if (isKnownNonNegative(Z, SQ.getWithInstruction(&I)) &&
        isKnownNonNegative(MinMax, SQ.getWithInstruction(&I))) {
      Pred = ICmpInst::getFlippedSignednessPredicate(Pred);
    } else
      return nullptr;
  }
  SimplifyQuery Q = SQ.getWithInstruction(&I);
CODEEOF"}

